392→function createFixtureObject(descriptor, materialPalette, isSelected) {
393→  const builder = FIXTURE_BUILDERS[descriptor.fixtureType];
394→  if (!builder) {
395→    return createBoxObject(descriptor, materialPalette, isSelected);
396→  }
397→
398→  const group = new THREE.Group();
399→  const W = descriptor.size.x;
400→  const H = descriptor.size.y;
401→  const D = descriptor.size.z;
402→
403→  builder(group, W, H, D, materialPalette, isSelected);
404→
405→  group.position.copy(planPointToWorld(descriptor.center, descriptor.baseElevation));
406→  group.rotation.y = planAngleToWorldRotation(descriptor.rotation);
407→
408→  return group;
409→}
