411→// ── Dispatcher ──
412→
413→function createObjectForDescriptor(descriptor, materialPalette, isSelected) {
414→  if (descriptor.geometry === 'prism') {
415→    return createPrismObject(descriptor, materialPalette, isSelected);
416→  }
417→
418→  if (descriptor.geometry === 'stair') {
419→    return createStairObject(descriptor, materialPalette, isSelected);
420→  }
421→
422→  if (descriptor.geometry === 'window') {
423→    return createWindowObject(descriptor, materialPalette, isSelected);
424→  }
425→
426→  if (descriptor.geometry === 'fixture') {
427→    return createFixtureObject(descriptor, materialPalette, isSelected);
428→  }
429→
430→  return createBoxObject(descriptor, materialPalette, isSelected);
431→}
432→
433→function matchesSelection(descriptor, selection) {
434→  if (!selection?.selectedId || selection.selectedType !== descriptor.kind) return false;
435→  return (descriptor.metadata?.sourceId || descriptor.id) === selection.selectedId;
436→}
437→
438→function assignPreviewMetadata(object, descriptor, floor) {
439→  const previewTarget = {
440→    kind: descriptor.kind,
441→    sourceId: descriptor.metadata?.sourceId || descriptor.id,
442→    floorId: descriptor.metadata?.floorId || floor.floorId,
443→  };
444→
445→  object.traverse((node) => {
446→    node.userData = {
447→      ...node.userData,
448→      previewTarget,
449→    };
450→  });
451→}
452→
453→export function buildPreviewObjectRoot(sceneDescriptor, materialPalette, selection = null) {
454→  const root = new THREE.Group();
455→  root.name = 'preview-root';
456→
457→  for (const floor of sceneDescriptor.floors) {
458→    const floorGroup = new THREE.Group();
459→    floorGroup.name = `floor-${floor.floorId}`;
460→    floorGroup.visible = floor.visible;
461→    floorGroup.userData = {
462→      floorId: floor.floorId,
463→      floorName: floor.name,
464→      elevation: floor.elevation,
465→    };
466→
467→    for (const descriptor of floor.objects) {
468→      const isSelected = matchesSelection(descriptor, selection);
469→      const object = createObjectForDescriptor(descriptor, materialPalette, isSelected);
470→      object.name = descriptor.id;
471→      object.userData = {
472→        id: descriptor.id,
473→        kind: descriptor.kind,
474→        metadata: descriptor.metadata,
475→      };
476→      assignPreviewMetadata(object, descriptor, floor);
477→      floorGroup.add(object);
478→    }
479→
480→    root.add(floorGroup);
481→  }
482→
483→  return root;
484→}
