  1→import { DOOR_HEIGHT, DOOR_SILL_HEIGHT, SLAB_ELEVATION, SLAB_THICKNESS, STAIR_RISERS, STAIR_RISER_HEIGHT, STAIR_TREAD_DEPTH, STAIR_WIDTH, WALL_HEIGHT, WINDOW_HEIGHT, WINDOW_SILL_HEIGHT } from '@/domain/defaults';
  2→import { createFloor } from '@/domain/models';
  3→import { createAnnotationSettings } from '@/domain/models';
  4→import { getDefaultActiveFloorId, getFloorElevation, getFloorLevelIndex, getFloorToFloorHeight, sortFloors } from '@/domain/floorModels';
  5→
  6→export function deserializeProject(json) {
  7→  if (!json || !json.version || !json.data) {
  8→    throw new Error('Invalid project data');
  9→  }
 10→  if (json.version !== 1) {
 11→    throw new Error(`Unsupported project version: ${json.version}`);
 12→  }
 13→
 14→  const project = json.data;
 15→
 16→  // Basic validation
 17→  if (!project.id || !project.name || !Array.isArray(project.floors)) {
 18→    throw new Error('Invalid project structure');
 19→  }
 20→
 21→  if (!Array.isArray(project.sheets)) {
 22→    project.sheets = [];
 23→  }
 24→
 25→  if (project.floors.length === 0) {
 26→    project.floors = [createFloor('Ground Floor', 0)];
 27→  }
 28→
 29→  for (const floor of project.floors) {
 30→    if (!floor.id || !Array.isArray(floor.walls)) {
 31→      throw new Error('Invalid floor structure');
 32→    }
 33→  }
 34→
 35→  // Backfill missing room fields for old saves
 36→  project.floors.forEach((floor, index) => {
 37→    if (!floor.name) floor.name = index === 0 ? 'Ground Floor' : `Floor ${index}`;
 38→    if (floor.levelIndex === undefined) {
 39→      floor.levelIndex = floor.level ?? index;
 40→    }
 41→    if (floor.floorToFloorHeight === undefined) {
 42→      floor.floorToFloorHeight = WALL_HEIGHT;
 43→    }
 44→    if (floor.elevation === undefined) {
 45→      floor.elevation = floor.level ?? (floor.levelIndex * floor.floorToFloorHeight);
 46→    }
 47→    delete floor.level;
 48→
 49→    if (!floor.rooms) floor.rooms = [];
 50→    for (const room of floor.rooms) {
 51→      if (!room.points) room.points = [];
 52→      if (room.area === undefined) room.area = 0;
 53→    }
 54→  });
 55→
 56→  // Backfill door/window type fields for old saves
 57→  for (const floor of project.floors) {
 58→    if (!floor.doors) floor.doors = [];
 59→    for (const door of floor.doors) {
 60→      if (!door.type) door.type = 'swing';
 61→      if (door.height === undefined) door.height = DOOR_HEIGHT;
 62→      if (door.sillHeight === undefined) door.sillHeight = DOOR_SILL_HEIGHT;
 63→    }
 64→    if (!floor.windows) floor.windows = [];
 65→    for (const win of floor.windows) {
 66→      if (!win.type) win.type = 'standard';
 67→      if (!win.openDirection) win.openDirection = 'left';
 68→      if (win.height === undefined) win.height = WINDOW_HEIGHT;
 69→      if (win.sillHeight === undefined) win.sillHeight = WINDOW_SILL_HEIGHT;
 70→    }
 71→    if (!floor.columns) floor.columns = [];
 72→    if (!floor.fixtures) floor.fixtures = [];
 73→    if (!floor.beams) floor.beams = [];
 74→    if (!floor.stairs) floor.stairs = [];
 75→    if (!floor.landings) floor.landings = [];
 76→    if (!floor.annotations) floor.annotations = [];
 77→    floor.annotationSettings = createAnnotationSettings(floor.annotationSettings || {});
 78→    // Migrate single slab → slabs array
 79→    if (floor.slab !== undefined) {
 80→      floor.slabs = floor.slab ? [floor.slab] : [];
 81→      delete floor.slab;
 82→    }
 83→    if (!Array.isArray(floor.slabs)) floor.slabs = [];
 84→    // Migrate single sectionCut → sectionCuts array
 85→    if (floor.sectionCut !== undefined) {
 86→      floor.sectionCuts = floor.sectionCut ? [floor.sectionCut] : [];
 87→      delete floor.sectionCut;
 88→    }
 89→    if (!Array.isArray(floor.sectionCuts)) floor.sectionCuts = [];
 90→    for (const wall of floor.walls) {
 91→      if (wall.height === undefined) wall.height = WALL_HEIGHT;
 92→      if (wall.startAttachment === undefined) wall.startAttachment = null;
 93→      if (wall.endAttachment === undefined) wall.endAttachment = null;
 94→    }
 95→    for (const column of floor.columns) {
 96→      if (column.showLabel === undefined) {
 97→        column.showLabel = Boolean(column.name);
 98→      }
 99→    }
100→    for (const fixture of floor.fixtures) {
101→      if (!fixture.fixtureType) fixture.fixtureType = 'kitchenTop';
102→      if (fixture.x === undefined) fixture.x = 0;
103→      if (fixture.y === undefined) fixture.y = 0;
104→      if (fixture.width === undefined) fixture.width = 600;
105→      if (fixture.depth === undefined) fixture.depth = 400;
106→      if (fixture.rotation === undefined) fixture.rotation = 0;
107→      if (fixture.name === undefined) fixture.name = '';
108→    }
109→    for (const beam of floor.beams) {
110→      if (beam.floorLevel === undefined) beam.floorLevel = getFloorElevation(floor, index);
111→    }
112→    for (const stair of floor.stairs) {
113→      if (!stair.startPoint) stair.startPoint = { x: 0, y: 0 };
114→      if (stair.width === undefined) stair.width = STAIR_WIDTH;
115→      if (stair.numberOfRisers === undefined) stair.numberOfRisers = STAIR_RISERS;
116→      if (stair.riserHeight === undefined) stair.riserHeight = STAIR_RISER_HEIGHT;
117→      if (stair.treadDepth === undefined) stair.treadDepth = STAIR_TREAD_DEPTH;
118→      if (stair.direction === undefined) {
119→        stair.direction = { angle: 0 };
120→      } else if (typeof stair.direction === 'number') {
121→        stair.direction = { angle: stair.direction };
122→      } else if (stair.direction.angle === undefined) {
123→        stair.direction.angle = 0;
124→      }
125→      if (stair.floorRelation === undefined) {
126→        stair.floorRelation = { fromFloorId: floor.id, toFloorId: floor.id };
127→      } else {
128→        if (stair.floorRelation.fromFloorId === undefined) stair.floorRelation.fromFloorId = floor.id;
129→        if (stair.floorRelation.toFloorId === undefined) stair.floorRelation.toFloorId = floor.id;
130→      }
131→      if (stair.startLandingAttachment === undefined) stair.startLandingAttachment = null;
132→      if (stair.endLandingAttachment === undefined) stair.endLandingAttachment = null;
133→    }
134→    for (const landing of floor.landings) {
135→      if (!landing.position) landing.position = { x: 0, y: 0 };
136→      if (landing.width === undefined) landing.width = 1000;
137→      if (landing.depth === undefined) landing.depth = 1000;
138→      if (landing.thickness === undefined) landing.thickness = 200;
139→      if (landing.elevation === undefined) landing.elevation = 0;
140→      if (landing.rotation === undefined) landing.rotation = 0;
141→    }
142→    for (const annotation of floor.annotations) {
143→      if (!annotation.id) {
144→        annotation.id = `anno_${floor.id}_${Math.random().toString(36).slice(2, 8)}`;
145→      }
146→      if (!annotation.type) annotation.type = 'dimension';
147→      if (!annotation.mode) annotation.mode = 'aligned';
148→      if (!annotation.startPoint) annotation.startPoint = { x: 0, y: 0 };
149→      if (!annotation.endPoint) annotation.endPoint = { x: 0, y: 0 };
150→      if (annotation.offset === undefined) annotation.offset = 300;
151→      if (annotation.textOverride === undefined) annotation.textOverride = '';
152→    }
153→    for (const slab of floor.slabs) {
