  kitchenTop: 900,
  toilet: 400,
  lavatory: 850,
  table: 750,
  tv: 750,
  sofa: 800,
};
```

**Location**: `/c/Users/johnm/modular apartment planner/src/three/viewer/buildPreviewObjects.js`

Each fixture has a custom builder function that constructs detailed 3D geometry:

- **`buildKitchenTopFixture`** (lines 260-280): Cabinet body + countertop + stovetop + 4 burners (cylinders) + sink
- **`buildToiletFixture`** (lines 282-297): Cistern box + cistern cap + bowl outer/inner + seat rim (all cylinders except boxes)
- **`buildLavatoryFixture`** (lines 299-319): Pedestal column + base + basin outer/inner/rim (cylinders) + faucet stem/spout
- **`buildTableFixture`** (lines 321-346): Tabletop + aprons + 4 legs (cylinders)
- **`buildTvFixture`** (lines 348-360): Screen panel + bezels + stand neck + stand base
- **`buildSofaFixture`** (lines 362-381): Base frame + backrest + left/right armrests + 3 seat cushions

**Dispatcher** (lines 383-409):
```javascript
const FIXTURE_BUILDERS = {
  kitchenTop: buildKitchenTopFixture,
  toilet: buildToiletFixture,
  // ... etc
};

function createFixtureObject(descriptor, materialPalette, isSelected) {
  const builder = FIXTURE_BUILDERS[descriptor.fixtureType];
  if (!builder) {
    return createBoxObject(descriptor, materialPalette, isSelected);  // Fallback
  }
  // ... build group with custom geometry
}
```

Fixtures use two helper functions:
- `addBox(group, materialKey, sx, sy, sz, px, py, pz, palette, sel)` - Creates BoxGeometry mesh
- `addCylinder(group, materialKey, rTop, rBot, h, segs, px, py, pz, palette, sel)` - Creates CylinderGeometry mesh

### 10. FIXTURE GEOMETRY (2D)

**Location**: `/c/Users/johnm/modular apartment planner/src/geometry/fixtureGeometry.js`

```javascript
export function fixtureOutline(fixture) {
  const hw = fixture.width / 2, hd = fixture.depth / 2;
  const { x: cx, y: cy } = fixture;
  const corners = [
    { x: cx - hw, y: cy - hd }, { x: cx + hw, y: cy - hd },
    { x: cx + hw, y: cy + hd }, { x: cx - hw, y: cy + hd },
  ];
  if (!fixture.rotation) return corners;
  return corners.map(p => rotate(p, { x: cx, y: cy }, fixture.rotation));
}

export function fixtureContainsPoint(fixture, point) {
  return pointInPolygon(point, fixtureOutline(fixture));
}
```

### 11. SERIALIZATION/DESERIALIZATION

**Location**: `/c/Users/johnm/modular apartment planner/src/persistence/deserialize.js` (lines 100-108)

Fixtures are backfilled with defaults for old saves:
```javascript
for (const fixture of floor.fixtures) {
  if (!fixture.fixtureType) fixture.fixtureType = 'kitchenTop';
  if (fixture.x === undefined) fixture.x = 0;
  if (fixture.y === undefined) fixture.y = 0;
  if (fixture.width === undefined) fixture.width = 600;
  if (fixture.depth === undefined) fixture.depth = 400;
  if (fixture.rotation === undefined) fixture.rotation = 0;
  if (fixture.name === undefined) fixture.name = '';
}
```

Serialization is simple - fixtures are stored as-is in floor.fixtures array.

### 12. MATERIAL KEYS FOR 3D

Fixtures use material keys like `fixture_kitchenTop`, `fixture_toilet`, etc. Combined with accent materials:
- `fixtureAccentDark` (dark metal/plastic)
- `fixtureAccentMetal` (brushed metal)
- `fixtureAccentCeramic` (white ceramic)
- `fixtureAccentWood` (wood apron/legs)
- `fixtureAccentFabric` (sofa cushions)

