321→function buildTableFixture(group, W, H, D, palette, sel) {
322→  const mat = 'fixture_table';
323→  // Tabletop
324→  addBox(group, mat, W, H * 0.05, D, 0, H * 0.975, 0, palette, sel);
325→  // Front apron
326→  addBox(group, mat, W * 0.90, H * 0.06, D * 0.03, 0, H * 0.92, D * 0.44, palette, sel);
327→  // Back apron
